import anthropic
import json

client = anthropic.Anthropic()

def execute_tool_safe(
    tool_use_id: str,
    tool_name: str,
    tool_input: dict,
    tool_fns: dict,          # tool_name -> callable
    expected_schema: dict | None = None,
    timeout_seconds: float = 10.0,
) -> ToolResult:
    """Execute one tool call and classify the outcome."""
    fn = tool_fns.get(tool_name)
    if fn is None:
        return ToolResult(
            tool_use_id=tool_use_id, tool_name=tool_name,
            status=ToolStatus.RUNTIME_ERROR, raw=None,
            feedback=f'Unknown tool: {tool_name}',
            retry_hint='Use one of the available tools.',
        )
    try:
        import signal
        def _timeout_handler(sig, frame):
            raise TimeoutError('tool timed out')
        signal.signal(signal.SIGALRM, _timeout_handler)
        signal.alarm(int(timeout_seconds))
        raw = fn(**tool_input)
        signal.alarm(0)
    except TimeoutError:
        return ToolResult(
            tool_use_id=tool_use_id, tool_name=tool_name,
            status=ToolStatus.TIMEOUT, raw=None,
            feedback=f'{tool_name} timed out after {timeout_seconds}s.',
            retry_hint='Try a simpler query or a different tool.',
        )
    except Exception as exc:
        return ToolResult(
            tool_use_id=tool_use_id, tool_name=tool_name,
            status=ToolStatus.RUNTIME_ERROR, raw=exc,
            feedback=f'{tool_name} raised: {exc}',
            retry_hint='Do not retry the same call. Try an alternative approach.',
        )
    if raw is None or raw == '' or raw == []:
        return ToolResult(
            tool_use_id=tool_use_id, tool_name=tool_name,
            status=ToolStatus.EMPTY, raw=raw,
            feedback=f'{tool_name} returned no results.',
            retry_hint='Try different parameters.',
        )
    if expected_schema:
        err = _validate_schema(raw, expected_schema)
        if err:
            return ToolResult(
                tool_use_id=tool_use_id, tool_name=tool_name,
                status=ToolStatus.SCHEMA_ERROR, raw=raw,
                feedback=f'{tool_name} output has wrong shape: {err}',
                retry_hint=f'Expected schema: {json.dumps(expected_schema)}',
            )
    return ToolResult(
        tool_use_id=tool_use_id, tool_name=tool_name,
        status=ToolStatus.SUCCESS, raw=raw,
        feedback=json.dumps(raw) if not isinstance(raw, str) else raw,
    )

def _validate_schema(raw, schema: dict) -> str:
    """Check required keys exist and types match. Returns error string or empty."""
    if not isinstance(raw, dict):
        return f'expected dict, got {type(raw).__name__}'
    for key, expected_type in schema.items():
        if key not in raw:
            return f'missing key: {key}'
        if not isinstance(raw[key], expected_type):
            return f'{key}: expected {expected_type.__name__}, got {type(raw[key]).__name__}'
    return ''

def build_retry_messages(
    messages: list[dict],
    failed_result: ToolResult,
    original_block,  # the tool_use block from the response
) -> list[dict]:
    """
    Append the error feedback and instruct the model to try again.
    The next model response will (hopefully) call the tool differently.
    """
    # First append the tool_result with the error
    tool_result_msg = {
        'role': 'user',
        'content': [make_feedback(failed_result)],
    }
    # Then append a follow-up user message requesting correction
    follow_up = {
        'role': 'user',
        'content': (
            f'The {failed_result.tool_name} call failed with status '
            f'{failed_result.status.value}. '
            f'{failed_result.retry_hint} '
            'Please try again with a corrected approach.'
        ),
    }
    return messages + [tool_result_msg, follow_up]

def run_with_tool_feedback(
    client,
    goal: str,
    tools: list[dict],
    tool_fns: dict,
    max_steps: int = 15,
    max_retries_per_tool: int = 2,
) -> str:
    messages = [{'role': 'user', 'content': goal}]
    tool_retry_counts: dict[str, int] = {}
    for _ in range(max_steps):
        resp = client.messages.create(
            model='claude-sonnet-4-6', max_tokens=1024,
            tools=tools, messages=messages,
        )
        messages.append({'role': 'assistant', 'content': resp.content})
        if resp.stop_reason == 'end_turn':
            return next(b.text for b in resp.content if hasattr(b, 'text'))
        results = []
        for block in resp.content:
            if block.type != 'tool_use':
                continue
            retries = tool_retry_counts.get(block.name, 0)
            if retries >= max_retries_per_tool:
                results.append(make_feedback(ToolResult(
                    tool_use_id=block.id, tool_name=block.name,
                    status=ToolStatus.RUNTIME_ERROR, raw=None,
                    feedback=f'{block.name} has failed {retries} times. Skipping.',
                )))
                continue
            result = execute_tool_safe(block.id, block.name, block.input, tool_fns)
            if result.status != ToolStatus.SUCCESS:
                tool_retry_counts[block.name] = retries + 1
            results.append(make_feedback(result))
        messages.append({'role': 'user', 'content': results})
    return 'Max steps reached'

# Some tools stream output (code execution, shell commands).
# Collect the full stream before passing to the model; optionally
# include the last N lines if the full output is too large.

from io import StringIO

def run_code_tool(
    code: str,
    max_output_lines: int = 50,
) -> ToolResult:
    """Execute Python code in a subprocess and capture stdout/stderr."""
    import subprocess, sys
    proc = subprocess.run(
        [sys.executable, '-c', code],
        capture_output=True, text=True, timeout=15,
    )
    stdout = proc.stdout.strip()
    stderr = proc.stderr.strip()
    if proc.returncode != 0:
        return ToolResult(
            tool_use_id='', tool_name='code_execution',
            status=ToolStatus.RUNTIME_ERROR,
            raw={'returncode': proc.returncode, 'stderr': stderr},
            feedback=f'Code exited with code {proc.returncode}.\nStderr: {stderr[:500]}',
            retry_hint='Fix the syntax or logic error and resubmit.',
        )
    lines = stdout.splitlines()
    if len(lines) > max_output_lines:
        output = '\n'.join(lines[-max_output_lines:])
        output = f'[...{len(lines) - max_output_lines} lines omitted...]\n' + output
    else:
        output = stdout
    if not output:
        return ToolResult(
            tool_use_id='', tool_name='code_execution',
            status=ToolStatus.EMPTY, raw=stdout,
            feedback='Code ran successfully but produced no output.',
            retry_hint='Add print() statements to show results.',
        )
    return ToolResult(
        tool_use_id='', tool_name='code_execution',
        status=ToolStatus.SUCCESS, raw=stdout,
        feedback=output,
    )

# Idempotency guard: record which write operations have been
# confirmed so that a retry loop does not duplicate them.

from dataclasses import dataclass, field
import hashlib

@dataclass
class IdempotencyGuard:
    _done: set[str] = field(default_factory=set)

    def key(self, tool_name: str, tool_input: dict) -> str:
        payload = f'{tool_name}:{sorted(tool_input.items())}'
        return hashlib.sha1(payload.encode()).hexdigest()[:12]

    def already_ran(self, tool_name: str, tool_input: dict) -> bool:
        return self.key(tool_name, tool_input) in self._done

    def mark_done(self, tool_name: str, tool_input: dict) -> None:
        self._done.add(self.key(tool_name, tool_input))

guard = IdempotencyGuard()

def execute_with_guard(
    tool_name: str,
    tool_input: dict,
    fn,
) -> ToolResult:
    if guard.already_ran(tool_name, tool_input):
        return ToolResult(
            tool_use_id='', tool_name=tool_name,
            status=ToolStatus.SUCCESS, raw=None,
            feedback=f'{tool_name} already completed with these inputs. Result is unchanged.',
        )
    result = fn()
    if result.status == ToolStatus.SUCCESS:
        guard.mark_done(tool_name, tool_input)
    return result
